// sanitizeLabelValue cleans and truncates a label value
func sanitizeLabelValue(value string) string {
	// Remove any characters not in the allowlist
	sanitized := sanitizeLabelRegex.ReplaceAllString(value, "_")

	// Truncate to max length
	if len(sanitized) > maxLabelValueLength {
		sanitized = sanitized[:maxLabelValueLength]
	}

	if sanitized == "" {
		sanitized = "unknown"
	}

	return sanitized
}

// normalizeEndpoint maps a request path to an allowed endpoint or "other"
func normalizeEndpoint(path string) string {
	// Check against allowlist - do NOT use the raw path as a label
	if allowedEndpoints[path] {
		return path
	}

	// Try prefix matching for parameterized routes
	for endpoint := range allowedEndpoints {
		if len(path) > len(endpoint) && path[:len(endpoint)] == endpoint {
			// Return the base endpoint, not the parameterized version
			// This prevents /api/v1/users/12345 from creating unique labels per user ID
			return endpoint
		}
	}

	return "other"
}

// normalizeMethod validates and normalizes HTTP method
func normalizeMethod(method string) string {
	if allowedMethods[method] {
		return method
	}
	return "OTHER"
}

// statusCodeBucket converts a status code to a bucket string
func statusCodeBucket(code int) string {
	switch {
	case code >= 200 && code < 300:
		return "2xx"
	case code >= 300 && code < 400:
		return "3xx"
	case code >= 400 && code < 500:
		return "4xx"
	case code >= 500 && code < 600:
		return "5xx"
	default:
		return "5xx"
	}
}

